import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSSecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize and encode user input to prevent XSS attacks
        String safeUserInput = sanitizeInput(userInput);

        String output = "<h1>Welcome " + safeUserInput + "!</h1>";

        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String sanitizeInput(String userInput) {
        // Implement your own logic to sanitize and encode user input
        // Here is an example using OWASP Java Encoder library
        return org.owasp.encoder.Encode.forHtml(userInput);
    }
}

